/* rateMapper.getRateMgmtList */
SELECT B.CD_DSC AS RATE_GRP_NM , A.RATE_GRP_CD , A.RATE_CD , A.RATE_NM , A.PAY_CL_CD , FN_GET_CODENM('CMN0032', A.PAY_CL_CD) AS PAY_CL_CD_NM , A.RATE_TYPE , C.CD_DSC AS RATE_TYPE_NM , A.DATA_TYPE , A.BASE_AMT , A.FREE_CALL_CNT , DECODE(FREE_CALL_CNT , NULL, '' , NVL((SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'SALE0001' AND CD_DSC = FREE_CALL_CNT AND USG_YN = 'Y') , 'A1')) AS FREE_CALL_CD , A.NW_IN_CALL_CNT , DECODE(NW_IN_CALL_CNT , NULL, '' , NVL((SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'SALE0002' AND CD_DSC = NW_IN_CALL_CNT AND USG_YN = 'Y') , 'A1')) AS NW_IN_CALL_CD , A.NW_OUT_CALL_CNT , A.FREE_SMS_CNT , DECODE(FREE_SMS_CNT , NULL, '' , NVL((SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'SALE0003' AND CD_DSC = FREE_SMS_CNT AND USG_YN = 'Y') , 'A1')) AS FREE_SMS_CD , A.FREE_DATA_CNT , DECODE(FREE_DATA_CNT , NULL, '' , NVL((SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'SALE0004' AND CD_DSC = FREE_DATA_CNT AND USG_YN = 'Y') , 'A1')) AS FREE_DATA_CD , A.APPL_STRT_DT , A.APPL_END_DT , A.RMK , FN_GET_USRNM(A.REGST_ID) AS REGST_NM , TO_CHAR(A.REGST_DTTM, 'YYYYMMDDHH24MISS') REGST_DTTM , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYYMMDDHH24MISS') RVISN_DTTM , FN_GET_CODENM('ORG0050', A.ONLINE_TYPE_CD) AS ONLINE_TYPE_NM , A.ONLINE_TYPE_CD , FN_GET_CODENM('MSP0008', A.SERVICE_TYPE) AS SERVICE_TYPE_NM , A.SERVICE_TYPE , #{stdrDt} AS STDR_DT , A.FREE_CALL_CL_CD , A.CMNT
, A.STTC_YN , A.ONLINE_CAN_YN , A.CAN_CMNT
,A.REMIND_YN ,A.REMIND_PROD_TYPE ,FN_GET_CODENM('CMN0282', A.REMIND_PROD_TYPE) AS REMIND_PROD_TYPE_NM
,DECODE(A.JEHU_PROD_TYPE, NULL, 'N', 'Y') AS JEHU_YN ,A.JEHU_PROD_TYPE
,A.ONLINE_CAN_DAY FROM MSP_RATE_MST A , CMN_GRP_CD_MST B , CMN_GRP_CD_MST C WHERE A.RATE_GRP_CD = B.CD_VAL(+) AND B.GRP_ID(+) = 'CMN0046' /* 요금제그룹 */ AND A.RATE_TYPE = C.CD_VAL AND C.GRP_ID = 'CMN0047' /* 요금제유형 */ AND #{stdrDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT
AND A.RATE_GRP_CD = #{rateGrpCd}
AND A.SERVICE_TYPE = #{serviceType}
AND UPPER(A.RATE_NM) LIKE '%' || UPPER( #{searchVal} ) || '%'
AND UPPER(A.RATE_CD) LIKE '%' || UPPER( #{searchVal} ) || '%'
AND A.PAY_CL_CD = #{payClCd}
AND A.RATE_TYPE = #{rateType}
ORDER BY A.APPL_STRT_DT DESC

/* rateMapper.getRateCdChk */
SELECT	COUNT(1) CHK
FROM	MSP_RATE_MST
WHERE	RATE_CD	= #{rateCd}

mapper.insert:
/* rateMapper.insertRateCd */
MERGE INTO MSP_RATE_MST
USING DUAL ON ( RATE_CD = #{rateCd, jdbcType=VARCHAR} )
WHEN MATCHED THEN
    UPDATE SET
        RATE_GRP_CD = #{rateGrpCd}
        , APPL_END_DT = #{applEndDt, jdbcType=VARCHAR}
        , RMK = #{rmk, jdbcType=VARCHAR}
        , RVISN_ID = #{userId, jdbcType=VARCHAR}
        , RVISN_DTTM = SYSDATE
        , ONLINE_TYPE_CD = #{onlineTypeCd, jdbcType=VARCHAR}
        , CMNT = #{cmnt, jdbcType=VARCHAR}
        , STTC_YN = DECODE(#{sttcYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , ONLINE_CAN_YN = DECODE(#{onlineCanYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , ONLINE_CAN_DAY = #{onlineCanDay, jdbcType=INTEGER}
        , CAN_CMNT = #{canCmnt, jdbcType=VARCHAR}
        , REMIND_YN = DECODE(#{remindYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , REMIND_PROD_TYPE = #{remindProdType, jdbcType=VARCHAR}
				, JEHU_PROD_TYPE = #{jehuProdType, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN
    INSERT (
        RATE_CD
        , RATE_NM
        , RATE_GRP_CD
        , APPL_STRT_DT
        , APPL_END_DT
        , PAY_CL_CD
        , RATE_TYPE
        , DATA_TYPE
        , BASE_AMT
        , FREE_CALL_CL_CD
        , FREE_CALL_CNT
        , NW_IN_CALL_CNT
        , NW_OUT_CALL_CNT
        , FREE_SMS_CNT
        , FREE_DATA_CNT
        , RMK
        , REGST_ID
        , REGST_DTTM
        , RVISN_ID
        , RVISN_DTTM
        , ONLINE_TYPE_CD
        , SERVICE_TYPE
        , CMNT
        , STTC_YN
        , ONLINE_CAN_YN
        , ONLINE_CAN_DAY
        , CAN_CMNT
        , REMIND_YN
        , REMIND_PROD_TYPE
        , JEHU_PROD_TYPE
    )VALUES(
        UPPER( #{rateCd, jdbcType=VARCHAR} )
        , UPPER( #{rateNm, jdbcType=VARCHAR} )
        , #{rateGrpCd, jdbcType=VARCHAR}
        , TO_CHAR(SYSDATE, 'YYYYMMDD')
        , '99991231'
        , #{payClCd, jdbcType=VARCHAR}
        , #{rateType, jdbcType=VARCHAR}
        , #{dataType, jdbcType=VARCHAR}
        , #{baseAmt, jdbcType=INTEGER}
        , #{freeCallClCd, jdbcType=VARCHAR}
        , #{freeCallCnt, jdbcType=VARCHAR}
        , #{nwInCallCnt, jdbcType=VARCHAR}
        , #{nwOutCallCnt, jdbcType=VARCHAR}
        , #{freeSmsCnt, jdbcType=VARCHAR}
        , #{freeDataCnt, jdbcType=VARCHAR}
        , #{rmk, jdbcType=VARCHAR}
        , #{userId, jdbcType=VARCHAR}
        , SYSDATE
        , #{userId, jdbcType=VARCHAR}
        , SYSDATE
        , #{onlineTypeCd, jdbcType=VARCHAR}
        , #{serviceType, jdbcType=VARCHAR}
        , #{cmnt, jdbcType=VARCHAR}
        , DECODE(#{sttcYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , DECODE(#{onlineCanYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , #{onlineCanDay, jdbcType=INTEGER}
        , #{canCmnt, jdbcType=VARCHAR}
        , DECODE(#{remindYn, jdbcType=VARCHAR}, 'Y', 'Y', 'N')
        , #{remindProdType, jdbcType=VARCHAR}
				, #{jehuProdType, jdbcType=VARCHAR}
    )

