/* rateMapper.getPlcyComboList */ SELECT A.SALE_PLCY_CD AS VALUE, A.SALE_PLCY_NM AS TEXT FROM MSP_SALE_PLCY_MST A, MSP_SALE_ORGN_MST B
, MSP_SALE_PRDT_MST C
, MSP_SALE_RATE_MST D
WHERE A.SALE_PLCY_CD = B.SALE_PLCY_CD AND A.CNFM_YN = 'Y'
AND A.SALE_PLCY_CD = C.SALE_PLCY_CD
