AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN A.SALE_STRT_DTTM AND A.SALE_END_DTTM
AND #{stdrDt} || TO_CHAR(SYSDATE, 'HH24MISS') BETWEEN A.SALE_STRT_DTTM AND A.SALE_END_DTTM
AND B.ORGN_ID = #{sessionUserOrgnId}
AND B.ORGN_ID = #{orgnId}
AND C.PRDT_ID = #{prdtId}
AND D.RATE_CD = #{rateCd}
ORDER BY 2

