mapper.select:
/* rateMapper.getRateMgmtListExcel */ SELECT B.CD_DSC AS rateGrpNm , A.RATE_GRP_CD AS rateGrpCd , A.RATE_CD AS rateCd , A.RATE_NM AS rateNm , TO_CHAR(TO_DATE(A.APPL_STRT_DT, 'YYYYMMDD'),'YYYY-MM-DD') AS applStrtDt , A.PAY_CL_CD AS payClCd , FN_GET_CODENM('CMN0032', A.PAY_CL_CD) AS payClCdNm , A.SERVICE_TYPE AS serviceType , FN_GET_CODENM('MSP0008', A.SERVICE_TYPE) AS serviceTypeNm , A.RATE_TYPE AS rateType , FN_GET_CODENM('CMN0047', A.RATE_TYPE) AS rateTypeNm , A.DATA_TYPE AS dataType , A.BASE_AMT AS baseAmt , A.FREE_CALL_CNT AS freeCallCnt , A.NW_IN_CALL_CNT AS nwInCallCnt , A.NW_OUT_CALL_CNT AS nwOutCallCnt , A.FREE_SMS_CNT AS freeSmsCnt , A.FREE_DATA_CNT AS freeDataCnt , A.ONLINE_TYPE_CD AS onlineTypeCd , FN_GET_CODENM('ORG0050', A.ONLINE_TYPE_CD) AS onlineTypeNm , C.AGRM_TRM AS agrmTrm , C.TM_AMT AS tmAmt , C.RT_AMT AS rtAmt , C.SP_AMT AS spAmt , D.TM_AMT12 AS tmAmt12 , D.TM_AMT18 AS tmAmt18 , D.RT_AMT12 AS rtAmt12 , D.RT_AMT18 AS rtAmt18 , D.SP_AMT12 AS spAmt12 , D.SP_AMT18 AS spAmt18 FROM MSP_RATE_MST A , CMN_GRP_CD_MST B , ( SELECT RATE_CD , AGRM_TRM , NVL(SUM(DECODE(A.SPRT_TP, 'KD', NVL(A.DC_AMT, 0))),0) AS TM_AMT , NVL(SUM(DECODE(A.SPRT_TP, 'PM', NVL(A.DC_AMT, 0))),0) AS RT_AMT , NVL(SUM(DECODE(A.SPRT_TP, 'SM', NVL(A.DC_AMT, 0))),0) AS SP_AMT , MAX(DECODE(A.SPRT_TP, 'PM', A.APPL_STRT_DTTM, 'SM', A.APPL_STRT_DTTM)) AS APPL_STRT_DTTM , MAX(DECODE(A.SPRT_TP, 'PM', A.APPL_END_DTTM, 'SM', A.APPL_END_DTTM)) AS APPL_END_DTTM FROM MSP_RATE_SPEC A WHERE #{stdrDt} || '000000' BETWEEN A.APPL_STRT_DTTM AND A.APPL_END_DTTM GROUP BY A.RATE_CD, A.AGRM_TRM ) C , ( SELECT RATE_CD , AGRM_TRM , MAX(DECODE(SPRT_TP,'KD', NVL(CC_AMT12, 0),0)) AS TM_AMT12 , MAX(DECODE(SPRT_TP,'KD', NVL(CC_AMT18, 0),0)) AS TM_AMT18 , MAX(DECODE(SPRT_TP,'PM', NVL(CC_AMT12, 0),0)) AS RT_AMT12 , MAX(DECODE(SPRT_TP,'PM', NVL(CC_AMT18, 0),0)) AS RT_AMT18 , MAX(DECODE(SPRT_TP,'SM', NVL(CC_AMT12, 0),0)) AS SP_AMT12 , MAX(DECODE(SPRT_TP,'SM', NVL(CC_AMT18, 0),0)) AS SP_AMT18 FROM MSP_RATE_CANCEL_SPEC WHERE #{stdrDt} || '000000' BETWEEN APPL_STRT_DTTM AND APPL_END_DTTM GROUP BY RATE_CD, AGRM_TRM ) D WHERE A.RATE_GRP_CD = B.CD_VAL(+) AND B.GRP_ID(+) = 'CMN0046' /* 요금제그룹 */ AND #{stdrDt} BETWEEN A.APPL_STRT_DT AND A.APPL_END_DT
AND A.RATE_GRP_CD = #{rateGrpCd}
AND UPPER(A.RATE_NM) LIKE '%' || UPPER( #{searchVal} ) || '%'
AND UPPER(A.RATE_CD) LIKE '%' || UPPER( #{searchVal} ) || '%'
AND A.PAY_CL_CD = #{payClCd}
AND A.SERVICE_TYPE = #{serviceType}
AND A.RATE_CD = C.RATE_CD(+) AND C.RATE_CD = D.RATE_CD(+) AND C.AGRM_TRM = D.AGRM_TRM(+) ORDER BY A.PAY_CL_CD, A.DATA_TYPE DESC, DECODE(A.RATE_TYPE,'02','1','00','2','3') DESC, A.RATE_CD, C.AGRM_TRM

